#include <bits/stdc++.h>
using namespace std;

int d[1005], a[1005][1005], p[1030], cur = 0;
int n = 500, m, s = 0;
void dfs(int u)
{
	for(int v = 1; v <= n; v++)
	{
		if(a[u][v] == 0) continue;
		a[u][v]--;
		a[v][u]--;
		dfs(v);
	}
	p[++cur] = u;
}

int main()
{

	cin >> m;
	for(int i = 1; i <= m; i++)
	{
		int x, y;
		cin >> x >> y;
		a[x][y]++;
		a[y][x]++;
		d[x]++;
		d[y]++;
	}
	for(int i = 1; i <= n; i++)
		if(d[i] % 2) {s = i;break;}
	if(s == 0)
		for(int i = 1; i <= n; i++)
			if(d[i]) {s = i;break;}
	dfs(s);
	for(int i = cur; i > 0; i--)
		cout << p[i] << endl;
}
